sql:
SELECT user_id, COALESCE(MAX(equity), 0) AS max_equity
FROM portfolio
GROUP BY user_id;

external_knowledge:
- 'champion of fortunes' refers to the user with the highest cumulative profit; 
- 'total wealth' refers to the sum of all profits (pnl) from their trades; 
- 'most triumphant win' refers to the trade with the highest profit; 
- 'deal details' include the trade ID, price, and quantity of the most profitable trade.

sql:
SELECT AVG(gain / (n_days * 24 * 60)) AS avg_daily_gain_30_days
FROM performance_metrics
WHERE n_days <= 30;

SELECT price, pos_side
FROM trades
WHERE pos_side = 'long' AND price > (SELECT AVG(price) FROM trades WHERE pos_side = 'long');
